          kind: "error",
          title: translate(authTimeout ? "cursor.authTimedOut.title" : "cursor.acpTimedOut.title"),
          summary: translate(authTimeout ? "cursor.authTimedOut.summary" : "cursor.acpTimedOut.summary"),
