  ReferenceDropParser,
  containsObsidianOpenUrl,
  createReferenceDropDebugInfo,
  decodeUriPath,
  extractReferenceCandidatesFromText,
  logReferenceDropDebug,
  normalizeReferenceInput,
  truncateDebugText
